import{_ as t,G as i,c as s,o as r,j as a,J as l,a6 as n,a as d}from"./chunks/framework.D3uGTwuV.js";const b=JSON.parse('{"title":"更改文件实际位置保持正常访问","description":"","frontmatter":{},"headers":[],"relativePath":"技巧/更改文件实际位置保持正常访问.md","filePath":"技巧/更改文件实际位置保持正常访问.md","lastUpdated":1775109753000}'),c={name:"技巧/更改文件实际位置保持正常访问.md"};function p(g,e,h,f,_,k){const o=i("ArticleMetadata");return r(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[e[0]||(e[0]=a("h1",{id:"更改文件实际位置保持正常访问",tabindex:"-1"},[d("更改文件实际位置保持正常访问 "),a("a",{class:"header-anchor",href:"#更改文件实际位置保持正常访问","aria-label":"Permalink to “更改文件实际位置保持正常访问”"},"​")],-1)),l(o),e[1]||(e[1]=n('<p>要把 <code>C:\\Users\\Starry\\.iflow</code> 这类<strong>固定路径、无法在软件内改位置</strong>的文件夹移到其他盘，最稳妥的方法是用 <strong>Windows 符号链接（目录联接）</strong>：系统仍看原路径，但实际文件存在新盘，不影响软件运行。</p><h2 id="一、准备工作-必做" tabindex="-1">一、准备工作（必做） <a class="header-anchor" href="#一、准备工作-必做" aria-label="Permalink to “一、准备工作（必做）”">​</a></h2><ol><li><strong>关闭所有相关软件</strong>：确保 <code>.iflow</code> 文件夹没有被程序占用（否则无法移动）。</li><li><strong>备份数据</strong>：复制一份 <code>.iflow</code> 到别处，防止操作出错丢失文件。</li><li><strong>在目标盘新建目录</strong>：比如在 D 盘建 <code>D:\\AppData\\.iflow</code>（路径可自定义）。</li></ol><h2 id="二、操作步骤-管理员-cmd" tabindex="-1">二、操作步骤（管理员 CMD） <a class="header-anchor" href="#二、操作步骤-管理员-cmd" aria-label="Permalink to “二、操作步骤（管理员 CMD）”">​</a></h2><ol><li>按 <code>Win + X</code> → 选择 <strong>Windows 终端（管理员）</strong> 或 <strong>命令提示符（管理员）</strong>。</li><li><strong>移动原文件夹到新位置</strong>：</li></ol><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>move &quot;C:\\Users\\Starry\\.iflow&quot; &quot;D:\\AppData\\&quot;</span></span></code></pre></div><p>执行后，原 <code>.iflow</code> 会被移到 <code>D:\\AppData\\.iflow</code>。</p><ol start="3"><li><strong>创建目录联接（符号链接）</strong>：</li></ol><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mklink /J &quot;C:\\Users\\Starry\\.iflow&quot; &quot;D:\\AppData\\.iflow&quot;</span></span></code></pre></div><pre><code>- `/J` 表示创建**目录联接**（适合文件夹）。\n- 命令成功会提示：`为 C:\\Users\\Starry\\.iflow &lt;&lt;===&gt;&gt; D:\\AppData\\.iflow 创建的联接`。\n</code></pre><ol start="4"><li>验证：打开 <code>C:\\Users\\Starry\\.iflow</code>，看到的是 D 盘里的文件，C 盘空间已释放。</li></ol><h2 id="三、常见问题与注意" tabindex="-1">三、常见问题与注意 <a class="header-anchor" href="#三、常见问题与注意" aria-label="Permalink to “三、常见问题与注意”">​</a></h2><ul><li><strong>文件被占用</strong>：关闭所有用到 <code>.iflow</code> 的软件，再重试 <code>move</code> 命令。</li><li><strong>权限不足</strong>：必须用<strong>管理员身份</strong>打开终端。</li><li><strong>误删链接</strong>：删除 <code>C:\\Users\\Starry\\.iflow</code> 这个链接，不会删 D 盘的真实文件；但直接删 D 盘文件会导致链接失效。</li><li><strong>恢复原状</strong>：删除 C 盘的链接，再把 D 盘的 <code>.iflow</code> 移回 <code>C:\\Users\\Starry\\</code> 即可。</li></ul><h2 id="四、其他场景-可选" tabindex="-1">四、其他场景（可选） <a class="header-anchor" href="#四、其他场景-可选" aria-label="Permalink to “四、其他场景（可选）”">​</a></h2><ul><li>若软件<strong>支持在设置里改缓存/数据路径</strong>：优先在软件内改，最安全。</li><li>批量迁移多个文件夹：可用 <code>robocopy</code> 复制 + <code>mklink</code> 链接，适合大量目录迁移。</li></ul>',15))])}const m=t(c,[["render",p]]);export{b as __pageData,m as default};
